"""matplotlib.backend_bases — base backend classes."""


class RendererBase:
    def draw_path(self, gc, path, transform, rgbFace=None): pass
    def draw_image(self, gc, x, y, im, transform=None): pass
    def draw_text(self, gc, x, y, s, prop, angle, ismath=False, mtext=None): pass
    def get_text_width_height_descent(self, s, prop, ismath): return (0, 0, 0)
    def points_to_pixels(self, points): return points
    def get_canvas_width_height(self): return (640, 480)
    def new_gc(self): return GraphicsContextBase()
    def open_group(self, s, gid=None): pass
    def close_group(self, s): pass


class GraphicsContextBase:
    def set_foreground(self, fg, isRGBA=False): pass
    def set_graylevel(self, frac): pass
    def set_linewidth(self, w): pass
    def set_linestyle(self, style): pass
    def set_capstyle(self, cs): pass
    def set_joinstyle(self, js): pass
    def set_dashes(self, dash_offset, dash_list): pass
    def set_alpha(self, alpha): pass
    def set_clip_rectangle(self, rectangle): pass
    def set_clip_path(self, path): pass
    def set_antialiased(self, b): pass
    def set_hatch(self, hatch): pass
    def get_linewidth(self): return 1.0
    def get_rgb(self): return (0, 0, 0, 1)
    def restore(self): pass
    def copy_properties(self, gc): pass


class FigureCanvasBase:
    def __init__(self, figure=None):
        self.figure = figure
        self._callbacks = {}

    def draw(self): pass
    def draw_idle(self): pass
    def blit(self, bbox=None): pass
    def resize(self, w, h): pass
    def get_width_height(self, *, physical=False): return (640, 480)
    def print_figure(self, filename, **kwargs): pass
    def get_default_filetype(self): return 'png'
    def get_supported_filetypes(self): return {'png': 'PNG', 'pdf': 'PDF', 'svg': 'SVG'}
    def get_supported_filetypes_grouped(self): return {}
    def mpl_connect(self, s, func):
        self._callbacks.setdefault(s, []).append(func)
        return len(self._callbacks[s]) - 1
    def mpl_disconnect(self, cid): pass
    def flush_events(self): pass
    def start_event_loop(self, timeout=0): pass
    def stop_event_loop(self): pass


class FigureManagerBase:
    def __init__(self, canvas, num):
        self.canvas = canvas
        self.num = num

    def show(self): pass
    def destroy(self): pass
    def full_screen_toggle(self): pass
    def resize(self, w, h): pass
    def set_window_title(self, title): pass
    def get_window_title(self): return ''


class NavigationToolbar2:
    toolitems = ()
    def __init__(self, canvas): self.canvas = canvas
    def home(self, *args): pass
    def back(self, *args): pass
    def forward(self, *args): pass
    def pan(self, *args): pass
    def zoom(self, *args): pass
    def save_figure(self, *args): pass
    def configure_subplots(self, *args): pass


class ToolContainerBase:
    pass


class StatusbarBase:
    pass


class Event:
    def __init__(self, name, canvas, guiEvent=None):
        self.name = name
        self.canvas = canvas
        self.guiEvent = guiEvent


class MouseEvent(Event):
    def __init__(self, name, canvas, x, y, button=None, key=None,
                 step=0, dblclick=False, guiEvent=None):
        super().__init__(name, canvas, guiEvent)
        self.x = x
        self.y = y
        self.button = button
        self.key = key
        self.step = step
        self.dblclick = dblclick
        self.xdata = x
        self.ydata = y
        self.inaxes = None


class KeyEvent(Event):
    def __init__(self, name, canvas, key, x=0, y=0, guiEvent=None):
        super().__init__(name, canvas, guiEvent)
        self.key = key
        self.x = x
        self.y = y


class ResizeEvent(Event):
    def __init__(self, name, canvas):
        super().__init__(name, canvas)
        self.width, self.height = canvas.get_width_height()


class CloseEvent(Event):
    pass


class LocationEvent(Event):
    def __init__(self, name, canvas, x, y, guiEvent=None):
        super().__init__(name, canvas, guiEvent)
        self.x = x
        self.y = y
        self.xdata = x
        self.ydata = y
        self.inaxes = None


class DrawEvent(Event):
    def __init__(self, name, canvas, renderer):
        super().__init__(name, canvas)
        self.renderer = renderer


class PickEvent(Event):
    def __init__(self, name, canvas, mouseevent, artist, **kwargs):
        super().__init__(name, canvas)
        self.mouseevent = mouseevent
        self.artist = artist
